  1	import * as React from 'react';
  2	import { connect } from 'react-redux';
  3	import {
  4	  Button,
  5	  TextInput,
  6	  Tooltip,
  7	  Divider,
  8	  Badge,
  9	  Checkbox,
 10	  Dropdown,
 11	  MenuToggleElement,
 12	  MenuToggle,
 13	  DropdownList
 14	} from '@patternfly/react-core';
 15	import { activeClustersSelector, clusterFilterSelector } from '../../store/Selectors';
 16	import { ClusterActions } from '../../actions/ClusterAction';
 17	import { MeshCluster } from '../../types/Mesh';
 18	import {
 19	  BoundingClientAwareComponent,
 20	  PropertyType
 21	} from '../../components/BoundingClientAwareComponent/BoundingClientAwareComponent';
 22	import { KialiIcon } from 'config/KialiIcon';
 23	import { KialiAppState } from '../../store/Store';
 24	import { KialiDispatch } from '../../types/Redux';
 25	import { serverConfig } from '../../config';
 26	import { kialiStyle } from 'styles/StyleUtils';
 27	
 28	type ReduxProps = {
 29	  activeClusters: MeshCluster[];
 30	  clusters: MeshCluster[];
 31	  filter: string;
 32	  setActiveClusters: (clusters: MeshCluster[]) => void;
 33	  setFilter: (filter: string) => void;
 34	};
 35	
 36	type ClusterDropdownProps = ReduxProps & {
 37	  clearAll: () => void;
 38	};
 39	
 40	type ClusterDropdownState = {
 41	  isBulkSelectorOpen: boolean;
 42	  isOpen: boolean;
 43	  selectedClusters: MeshCluster[];
 44	};
 45	
 46	const optionBulkStyle = kialiStyle({
 47	  marginLeft: '0.5rem',
 48	  position: 'relative',
 49	  top: '0.5rem'
 50	});
 51	
 52	const optionStyle = kialiStyle({ marginLeft: '1.0rem' });
 53	
 54	const optionLabelStyle = kialiStyle({ marginLeft: '0.5rem' });
 55	
 56	const headerStyle = kialiStyle({
 57	  margin: '0.5rem',
 58	  marginTop: 0,
 59	  width: '300px'
 60	});
 61	
 62	const marginBottom = 20;
 63	
 64	const clusterContainerStyle = kialiStyle({
 65	  overflow: 'auto'
 66	});
 67	
 68	const dividerStyle = kialiStyle({
 69	  paddingTop: '0.625rem'
 70	});
 71	
 72	const closeButtonStyle = kialiStyle({
 73	  borderTopLeftRadius: 0,
 74	  borderBottomLeftRadius: 0
 75	});
 76	
 77	export class ClusterDropdownComponent extends React.PureComponent<ClusterDropdownProps, ClusterDropdownState> {
 78	  constructor(props: ClusterDropdownProps) {
 79	    super(props);
 80	
 81	    this.state = {
 82	      isBulkSelectorOpen: false,
 83	      isOpen: false,
 84	      selectedClusters: [...this.props.activeClusters]
 85	    };
 86	  }
 87	
 88	  private clusterButtonText() {
 89	    if (this.state.selectedClusters.length === 0) {
 90	      return <span>Select Clusters</span>;
 91	    }
 92	
 93	    return (
 94	      <>
 95	        <span style={{ paddingRight: '0.75rem' }}>Cluster:</span>
 96	        {this.state.selectedClusters.length === 1 ? (
 97	          <span>{this.state.selectedClusters[0].name}</span>
 98	        ) : (
 99	          <Badge>{this.state.selectedClusters.length}</Badge>
100	        )}
101	      </>
102	    );
103	  }
104	
105	  private getBulkSelector() {
106	    const selectedClusters = this.filteredSelected();
107	    const numSelected = selectedClusters.length;
108	    const allSelected = numSelected === this.props.clusters.length;
109	    const anySelected = numSelected > 0;
110	    const someChecked = anySelected ? null : false;
111	    const isChecked = allSelected ? true : someChecked;
112	
113	    return (
114	      <div className={optionBulkStyle}>
115	        <Checkbox
116	          id="bulk-select-id"
117	          key="bulk-select-key"
118	          aria-label="Select all"
119	          isChecked={isChecked}
120	          onChange={() => {
121	            anySelected ? this.onBulkNone() : this.onBulkAll();
122	          }}
123	        ></Checkbox>
124	        <span className={optionLabelStyle}>Select all</span>
125	      </div>
126	    );
127	  }
128	
129	  private getHeader() {
130	    const hasFilter = !!this.props.filter;
131	
132	    return (
133	      <div className={headerStyle}>
134	        <span style={{ display: 'flex' }}>
135	          <TextInput
136	            aria-label="filter-cluster"
137	            type="text"
138	            name="cluster-filter"
139	            placeholder="Filter by Name..."
140	            value={this.props.filter}
141	            onChange={(_event, value: string) => this.onFilterChange(value)}
142	          />
143	          {hasFilter && (
144	            <Tooltip key="ot_clear_cluster_filter" position="top" content="Clear Filter by Name">
145	              <Button className={closeButtonStyle} onClick={this.clearFilter} isInline>
146	                <KialiIcon.Close />
147	              </Button>
148	            </Tooltip>
149	          )}
150	        </span>
151	        {this.getBulkSelector()}
152	        <Divider className={dividerStyle} />
153	      </div>
154	    );
155	  }
156	
157	  private getBody() {
158	    if (this.props.clusters.length > 0) {
159	      const selectedMap = this.state.selectedClusters.reduce((map, cluster) => {
160	        map[cluster.name] = cluster.name;
161	        return map;
162	      }, {});
163	
164	      const clusters = this.filtered().map((cluster: MeshCluster) => (
165	        <div
166	          className={optionStyle}
167	          id={`cluster-list-item[${cluster.name}]`}
168	          key={`cluster-list-item[${cluster.name}]`}
169	        >
170	          <input
171	            type="checkbox"
172	            value={cluster.name}
173	            checked={!!selectedMap[cluster.name]}
174	            onChange={this.onClusterToggled}
175	          />
176	          <span className={optionLabelStyle}>{cluster.name}</span>
177	        </div>
178	      ));
179	
180	      return (
181	        <>
182	          <BoundingClientAwareComponent
183	            className={clusterContainerStyle}
184	            maxHeight={{ type: PropertyType.VIEWPORT_HEIGHT_MINUS_TOP, margin: marginBottom }}
185	          >
186	            {clusters}
187	          </BoundingClientAwareComponent>
188	        </>
189	      );
190	    }
191	
192	    return <div className={optionStyle}>No clusters found</div>;
193	  }
194	
195	  render() {
196	    if (this.props.clusters.length > 1) {
197	      return (
198	        <Dropdown
199	          toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
200	            <MenuToggle
201	              ref={toggleRef}
202	              data-test="cluster-dropdown"
203	              id="cluster-selector"
204	              onClick={() => this.onToggle(!this.state.isOpen)}
205	              isExpanded={this.state.isOpen}
206	            >
207	              {this.clusterButtonText()}
208	            </MenuToggle>
209	          )}
210	          isOpen={this.state.isOpen}
211	          onOpenChange={(isOpen: boolean) => this.onToggle(isOpen)}
212	        >
213	          <DropdownList>
214	            {this.getHeader()}
215	            {this.getBody()}
216	          </DropdownList>
217	        </Dropdown>
218	      );
219	    } else {
220	      return null;
221	    }
222	  }
223	
224	  private onToggle = (isOpen: boolean) => {
225	    if (!isOpen) {
226	      this.props.setActiveClusters(this.state.selectedClusters);
227	      this.clearFilter();
228	    }
229	
230	    this.setState({
231	      isOpen
232	    });
233	  };
234	
235	  private onBulkAll = () => {
236	    const union = Array.from(new Set([...this.state.selectedClusters, ...this.filtered()]));
237	    this.setState({ selectedClusters: union });
238	  };
239	
240	  private onBulkNone = () => {
241	    const filtered = this.filtered();
242	    const remaining = this.state.selectedClusters.filter(s => filtered.findIndex(f => f.name === s.name) < 0);
243	    this.setState({ selectedClusters: remaining });
244	  };
245	
246	  onClusterToggled = event => {
247	    const cluster = event.target.value;
248	    const selectedClusters = !!this.state.selectedClusters.find(cl => cl.name === cluster)
249	      ? this.state.selectedClusters.filter(cl => cl.name !== cluster)
250	      : this.state.selectedClusters.concat(serverConfig.clusters[event.target.value]);
251	    this.setState({ selectedClusters: selectedClusters });
252	  };
253	
254	  private onFilterChange = (value: string) => {
255	    this.props.setFilter(value);
256	  };
257	
258	  private clearFilter = () => {
259	    this.props.setFilter('');
260	  };
261	
262	  private filtered = (): MeshCluster[] => {
263	    return this.props.clusters.filter(cl => cl.name.toLowerCase().includes(this.props.filter.toLowerCase()));
264	  };
265	
266	  private filteredSelected = (): MeshCluster[] => {
267	    const filtered = this.filtered();
268	    return this.state.selectedClusters.filter(s => filtered.findIndex(f => f.name === s.name) >= 0);
269	  };
270	}
271	
272	const mapStateToProps = (state: KialiAppState) => {
273	  return {
274	    clusters: Object.values(serverConfig.clusters),
275	    activeClusters: activeClustersSelector(state),
276	    filter: clusterFilterSelector(state)
277	  };
278	};
279	
280	const mapDispatchToProps = (dispatch: KialiDispatch) => {
281	  return {
282	    clearAll: () => {
283	      dispatch(ClusterActions.setActiveClusters([]));
284	    },
285	    setActiveClusters: (clusters: MeshCluster[]) => {
286	      dispatch(ClusterActions.setActiveClusters(clusters));
287	    },
288	    setFilter: (filter: string) => {
289	      dispatch(ClusterActions.setFilter(filter));
290	    }
291	  };
292	};
293	
294	export const ClusterDropdown = connect(mapStateToProps, mapDispatchToProps)(ClusterDropdownComponent);

